package main

import "sync"

var counter int

func increment(wg *sync.WaitGroup) {
    for i := 0; i < 1000; i++ {
        counter++
    }
    wg.Done()
}

func main() {
    var wg sync.WaitGroup
    wg.Add(2)
    go increment(&wg)
    go increment(&wg)
    wg.Wait()
    fmt.Println(counter)
}

